const API_BASE = '/api'

async function fetchJson<T>(url: string, options?: RequestInit): Promise<T> {
  const response = await fetch(url, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...options?.headers,
    },
  })
  if (!response.ok) {
    throw new Error(`API error: ${response.status} ${response.statusText}`)
  }
  return response.json()
}

export interface DashboardResponse {
  games: any[]
  supermax_lock: any | null
  total_games: number
  qualified_games: number
  today: string
}

export interface LiveScoresResponse {
  live_scores: Record<string, any>
  timestamp: number
}

export interface HistoryResponse {
  picks: any[]
  stats: {
    total: number
    wins: number
    losses: number
    pending: number
    win_rate: number
  }
}

export const api = {
  getDashboardData: () => fetchJson<DashboardResponse>(`${API_BASE}/dashboard_data`),

  getLiveScores: () => fetchJson<LiveScoresResponse>(`${API_BASE}/live_scores`),

  getHistoryData: () => fetchJson<HistoryResponse>(`${API_BASE}/history_data`),

  fetchGames: () =>
    fetchJson<{ success: boolean; message: string }>(`${API_BASE}/fetch_games`, {
      method: 'POST',
    }),

  fetchOdds: () =>
    fetchJson<{ success: boolean; message: string }>(`${API_BASE}/fetch_games`, {
      method: 'POST',
    }),

  postDiscord: (game?: any) =>
    fetchJson<{ success: boolean; message: string }>(`${API_BASE}/post_discord`, {
      method: 'POST',
      body: JSON.stringify({ game }),
    }),

  updateResult: (pickId: number, result: 'W' | 'L' | 'P') =>
    fetchJson<{ success: boolean }>(`${API_BASE}/history_data`, {
      method: 'POST',
      body: JSON.stringify({ action: 'update_result', pick_id: pickId, result }),
    }),

  addPick: (pick: {
    matchup: string
    league: string
    pick: string
    line: number
    edge: number
    is_lock?: boolean
    confidence_tier?: string
  }) =>
    fetchJson<{ success: boolean; pick: any }>(`${API_BASE}/history_data`, {
      method: 'POST',
      body: JSON.stringify({ action: 'add_pick', ...pick }),
    }),

  checkResults: () =>
    fetchJson<{ success: boolean }>(`${API_BASE}/check_results`, {
      method: 'POST',
    }),
}

export default api
